from collections import defaultdict

class Solution:
    def isPossible(self, nums: List[int]) -> bool:
        count = defaultdict(int)
        tails = defaultdict(int)

        for num in nums:
            count[num] += 1

        for num in nums:
            if count[num] > 0:
                if tails[num - 1] > 0:
                    tails[num - 1] -= 1
                    tails[num] += 1
                elif count[num] > 1:
                    count[num] -= 1
                    tails[num + 2] += 1
                else:
                    return False
                count[num] -= 1

        return True
